args.query:
SELECT c.id, c.subject, c.description, c.status, c.createddate, c.closeddate
FROM "Case" c
WHERE trim(replace(c.contactid,'#','')) IN (
  SELECT trim(replace(ConvertedContactId,'#','')) FROM Lead WHERE trim(replace(Id,'#',''))='00QWt0000089AekMAE'
)
OR trim(replace(c.accountid,'#','')) IN (
  SELECT trim(replace(ConvertedAccountId,'#','')) FROM Lead WHERE trim(replace(Id,'#',''))='00QWt0000089AekMAE'
)
ORDER BY c.createddate DESC
LIMIT 5;

